INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5df3ced2-32f3-4a09-8722-a50b198ccb98',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Project Structure — Vertical Slice vs MVC and When to Use Each$escape$,
  $escape$Fiber doesn't enforce a project layout, so teams default to flat MVC: `routes/`, `handlers/`, `models/`, `services/`. This works until your app grows — then cross-cutting changes touch six directories for one feature. Vertical slice flips the axis: organize by domain, not layer. Each feature folder owns its handler, service, and repository. Register routes by calling a `Register(router fiber.Router)` function on each feature's package — `app.Group("/users", middleware.Auth())` passed into `users.Register()`. Use `fiber.New()` at the app root, mount feature groups via `app.Mount()` or `app.Group()`, and keep `main.go` as pure wiring. Middleware like `limiter`, `compress`, and `requestid` attaches at the app or group level, not buried in handlers. For monorepos, `internal/` enforces package boundaries — nothing outside your module imports your domain logic. Vertical slice pays off fast in Fiber apps: adding a `/payments` feature means one new folder and one `Register()` call, zero changes elsewhere.$escape$,
  $escape$// internal/users/routes.go
func Register(r fiber.Router) {
	r.Post("/", CreateUser)
	r.Get("/:id", GetUser)
}

// internal/payments/routes.go
func Register(r fiber.Router) {
	r.Post("/charge", ChargeUser)
}

// main.go
app := fiber.New()
app.Use(requestid.New(), logger.New())

users.Register(app.Group("/users", middleware.Auth()))
payments.Register(app.Group("/payments", middleware.Auth()))

log.Fatal(app.Listen(":3000"))$escape$,
  $escape$go$escape$,
