INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f420d717-080b-485a-b53a-2fbb2b56afa8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Input Validation — Schema Validation and Structured Error Responses at the Boundary$escape$,
  $escape$Fiber has no built-in schema validator, so validation lives in a thin layer between `c.BodyParser()` and your handler logic. The idiomatic approach pairs Fiber with `go-playground/validator`: define your DTO as a struct with `validate:` tags, parse the body, then validate before touching business logic. Never trust parsed data without it — `BodyParser` only decodes; it doesn't constrain values.

For sanitization, strip whitespace and normalize strings before validation, not after. Use a global `ErrorHandler` in `fiber.Config` to intercept `*fiber.Error` and validation errors centrally, returning a consistent `{ error, fields }` JSON shape instead of scattering `c.Status().JSON()` calls across handlers. Register the validator once as an app-level dependency and inject it via closure. This keeps handlers lean: parse → sanitize → validate → delegate. Any failure before delegation returns 400 with field-level detail, making client integration predictable and eliminating ambiguous 500s caused by unvalidated upstream data reaching the database layer.$escape$,
  $escape$type CreatePostRequest struct {
	Title   string `json:"title" validate:"required,min=3,max=120"`
	Content string `json:"content" validate:"required,min=10"`
}

func createPostHandler(v *validator.Validate) fiber.Handler {
	return func(c *fiber.Ctx) error {
		var req CreatePostRequest
		if err := c.BodyParser(&req); err != nil {
			return fiber.NewError(fiber.StatusBadRequest, "invalid JSON")
		}
		req.Title = strings.TrimSpace(req.Title)
		req.Content = strings.TrimSpace(req.Content)
		if err := v.Struct(&req); err != nil {
			return c.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
				"error":  "validation failed",
				"fields": err.(validator.ValidationErrors).Error(),
			})
		}
		return c.Status(fiber.StatusCreated).JSON(fiber.Map{"ok": true})
	}
}$escape$,
  $escape$go$escape$,
