INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0db26e75-8057-4b1c-ab34-8e16711333f3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Testing — Unit vs Integration, Mocking HTTP, and Test Database Strategy$escape$,
  $escape$Fiber's `app.Test()` method is the cornerstone of its testing story — it accepts an `*http.Request` and returns an `*http.Response` without binding to a real port, making unit tests fast and isolated. For handler unit tests, construct your `fiber.App`, register only the route under test, and call `app.Test(httptest.NewRequest(...))`. For integration tests, wire the full middleware stack and a real test database — Fiber's middleware chain (CORS, JWT, rate limiter) must be exercised together to catch interaction bugs.

For mocking downstream HTTP calls, inject an `http.Client` into your service layer and swap it with a `httptest.NewServer`-backed client in tests — Fiber itself doesn't dictate this, but keeping clients injectable keeps handlers testable. For the database, prefer a real PostgreSQL instance via Docker (testcontainers-go) over SQLite shims; Fiber apps typically use pgx or sqlx directly, and dialect differences bite. Run `t.Cleanup()` to truncate tables between tests rather than rolling back transactions — it handles deferred side effects (triggers, audit logs) that rollbacks silently skip.$escape$,
  $escape$func TestPostHandler(t *testing.T) {
	app := fiber.New()
	svc := NewPostService(testDB) // real pg testcontainer
	app.Post("/posts", NewPostHandler(svc).Create)

	body := strings.NewReader(`{"title":"Go Fiber"}`)
	req := httptest.NewRequest(http.MethodPost, "/posts", body)
	req.Header.Set("Content-Type", "application/json")

	resp, err := app.Test(req, -1) // -1 = no timeout
	assert.NoError(t, err)
	assert.Equal(t, fiber.StatusCreated, resp.StatusCode)
	t.Cleanup(func() { truncateTable(testDB, "posts") })
}$escape$,
  $escape$go$escape$,
