INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9b601780-4b6b-4222-8935-30632ebddf1f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Serialization — DTOs, camelCase vs snake_case, and Null Handling Done Right$escape$,
  $escape$Fiber uses `encoding/json` by default, but struct tags are what actually control your wire format. When you define request/response DTOs, the `json:` tag governs field naming — use `json:"user_name"` for snake_case or `json:"userName"` for camelCase. Fiber's `c.BodyParser()` respects these same tags when deserializing incoming JSON, so your DTOs are symmetric in and out.

For null handling, lean on pointer types combined with `omitempty`. A `*string` field with `json:",omitempty"` is omitted entirely when nil — cleaner than sending `"field": null` to clients. If you need explicit nulls (e.g., PATCH semantics), keep the pointer but drop `omitempty`.

For high-throughput routes, swap the default encoder via `fiber.Config{JSONEncoder: sonic.Marshal, JSONDecoder: sonic.Unmarshal}` — Bytedance's sonic encoder is 3–5x faster than `encoding/json` and is a drop-in replacement. Your struct tags remain unchanged. Never call `json.Marshal` manually inside handlers; always go through `c.JSON()` so the encoder swap applies globally.$escape$,
  $escape$package main

import (
	"github.com/bytedance/sonic"
	"github.com/gofiber/fiber/v2"
)

type CreateUserRequest struct {
	Username string  `json:"username"`
	Email    string  `json:"email"`
	Bio      *string `json:"bio,omitempty"`
}

type UserResponse struct {
	ID       int     `json:"id"`
	Username string  `json:"username"`
	Bio      *string `json:"bio,omitempty"`
}

func main() {
	app := fiber.New(fiber.Config{
		JSONEncoder: sonic.Marshal,
		JSONDecoder: sonic.Unmarshal,
	})

	app.Post("/users", func(c *fiber.Ctx) error {
		var req CreateUserRequest
		if err := c.BodyParser(&req); err != nil {
			return fiber.ErrBadRequest
		}
		res := UserResponse{ID: 1, Username: req.Username, Bio: req.Bio}
		return c.JSON(res)
	})

	app.Listen(":3000")
}$escape$,
