INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '78827558-355f-4226-be70-6f8c24c45114',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Configuration — Env Vars, Config Structs, and Secrets Done Right$escape$,
  $escape$Fiber accepts a `fiber.Config` struct at initialization — use it to centralize app-level settings like timeouts, body limits, and error handlers rather than scattering them across handlers. Pair this with a typed `AppConfig` struct loaded from environment variables before `fiber.New()` is called.

Use `godotenv.Load()` in development to populate env vars from `.env`, but rely solely on real environment variables in production — never ship `.env` files. For secrets (DB passwords, API keys), read them once at startup into your config struct and never re-read from `os.Getenv` inside handlers; this avoids repeated syscalls and keeps secret access auditable in one place.

For validation, use the `validator` package on your config struct at boot — fail fast if `JWT_SECRET` is empty rather than panicking mid-request. Fiber's `fiber.Config.ErrorHandler` can then return clean JSON errors without leaking config values. Store sensitive fields as `string` (not logged types) and use `omitempty` with caution in marshaling paths to prevent accidental secret exposure.$escape$,
  $escape$package main

import (
	"log"
	"os"

	"github.com/gofiber/fiber/v2"
	"github.com/joho/godotenv"
)

type AppConfig struct {
	JWTSecret string
	DBURL     string
	Port      string
}

func loadConfig() AppConfig {
	_ = godotenv.Load() // no-op in prod
	cfg := AppConfig{
		JWTSecret: os.Getenv("JWT_SECRET"),
		DBURL:     os.Getenv("DATABASE_URL"),
		Port:      os.Getenv("PORT"),
	}
	if cfg.JWTSecret == "" || cfg.DBURL == "" {
		log.Fatal("missing required env vars: JWT_SECRET, DATABASE_URL")
	}
	if cfg.Port == "" {
		cfg.Port = "3000"
	}
	return cfg
}

func main() {
	cfg := loadConfig()
	app := fiber.New(fiber.Config{
		AppName:       "ByteAI API",
		ReadTimeout:   5 * time.Second,
		WriteTimeout:  10 * time.Second,
		BodyLimit:     1 * 1024 * 1024,
		ErrorHandler:  jsonErrorHandler,
	})
	app.Listen(":" + cfg.Port)
}$escape$,
