INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ca912667-cea7-47f0-b933-23d0ec525a7c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Dev Tooling — Hot Reload with Air and Scaffolding Your First App$escape$,
  $escape$Fiber has no built-in hot reload, but the Go ecosystem's de facto solution is `air` — a live-reloading watcher that rebuilds your binary on file changes. Drop an `.air.toml` at your project root to tune build commands, watch directories, and exclude paths like `tmp/`. For Fiber specifically, set `cmd = "go build -o ./tmp/main ."` and `bin = "./tmp/main"` — air will kill and restart the process cleanly on each save, preserving your `fiber.New()` config.

For scaffolding, `gofiber/recipes` on GitHub is the official starting point — clone a recipe (REST API, JWT auth, websockets, etc.) rather than hand-rolling boilerplate. Pair this with `go generate` directives to automate repetitive code: embed `//go:generate` above your route groups to regenerate OpenAPI specs or mock handlers via `mockgen`. The `fiber/v3` CLI (currently experimental) adds `fiber new <app>` for opinionated project layout with middleware pre-wired. Together, air + recipes + go generate covers 90% of Fiber's dev-loop friction.$escape$,
  $escape$# .air.toml — minimal Fiber hot-reload config
root = "."
tmp_dir = "tmp"

[build]
  cmd = "go build -o ./tmp/main ."
  bin = "./tmp/main"
  delay = 1000
  exclude_dir = ["tmp", "vendor", "testdata"]
  include_ext = ["go"]
  kill_delay = "500ms"

[log]
  time = true$escape$,
  $escape$bash$escape$,
