INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cd265ecd-eba9-4891-b51b-6a693170a885',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Observability — Health Checks, Prometheus Metrics, and OpenTelemetry Tracing in One Setup$escape$,
  $escape$Fiber's middleware ecosystem covers all three observability pillars with minimal boilerplate. For health checks, expose `/livez` (process alive) and `/readyz` (dependencies reachable — DB ping, cache check) as separate routes; Kubernetes probes treat them differently. For metrics, `fiberprometheus` auto-instruments every route with `http_requests_total`, `http_request_duration_seconds`, and in-flight gauges — mount it before your routes so no handler is missed. For distributed tracing, `otelfiber` from `gofiber/contrib` injects a span per request and propagates W3C `traceparent` headers downstream, letting you correlate Fiber traces with calls to gRPC services or external APIs in tools like Jaeger or Tempo. One critical detail: call `otelfiber.Middleware()` before `fiberprometheus` so trace IDs are available on the span when metrics are recorded. Use `fiber.New(fiber.Config{DisableStartupMessage: true})` in production to avoid stdout noise that pollutes structured log pipelines. All three integrations add under 2ms p99 overhead on commodity hardware.$escape$,
  $escape$package main

import (
	"github.com/ansrivas/fiberprometheus/v2"
	"github.com/gofiber/contrib/otelfiber"
	"github.com/gofiber/fiber/v2"
)

func main() {
	app := fiber.New(fiber.Config{DisableStartupMessage: true})

	app.Use(otelfiber.Middleware("my-service"))

	prom := fiberprometheus.New("my-service")
	prom.RegisterAt(app, "/metrics")
	app.Use(prom.Middleware)

	app.Get("/livez", func(c *fiber.Ctx) error {
		return c.SendStatus(fiber.StatusOK)
	})
	app.Get("/readyz", func(c *fiber.Ctx) error {
		if err := checkDependencies(); err != nil {
			return c.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{"error": err.Error()})
		}
		return c.SendStatus(fiber.StatusOK)
	})

	app.Listen(":3000")
}$escape$,
  $escape$go$escape$,
